class Solution {
public:
    string largestPalindrome(int n, int k) {
        string maxNum(n, '9');
        long long num = stol(maxNum);
        long long kLong = k;
        while (num % kLong != 0) {
            num--;
        }
        string result = to_string(num);
        if (result.size() == n) {
            return result;
        } else {
            return string(n, '0');
        }
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
energy implications: LOW
explanation: The solution starts from the largest n-digit number and decrements until it finds a number divisible by k, then checks if the number still has n digits. If not, it returns a number with n zeros. 
